const additionalEnglish6: SeedQuestion[] = [
  { section: 'english', question_text: 'Which sentence uses an apostrophe correctly for plural possessive?', passage: null, options: JSON.stringify(['A) The teachers lounge is down the hall.', 'B) The teachers\' lounge is down the hall.', 'C) The teacher\'s lounge\'s is down the hall.', 'D) The teachers\' lounge\'s is down the hall.']), correct_answer: 'B', explanation: 'Multiple teachers share the lounge: plural possessive = teachers\'.', incorrect_reasoning: JSON.stringify({ A: 'Missing apostrophe', C: 'Double possessive and singular', D: 'Double possessive' }), skill_tag: 'punctuation', difficulty: 'medium', strategy_tip: 'Plural possessive: noun + s + apostrophe (teachers\').' },
  { section: 'english', question_text: 'Which sentence demonstrates correct use of "affect" vs "effect"?', passage: null, options: JSON.stringify(['A) The rain will effect our plans.', 'B) The rain will affect our plans.', 'C) The affect of rain was minimal.', 'D) We effected by rain.']), correct_answer: 'B', explanation: 'Affect is typically a verb meaning to influence. Effect is typically a noun.', incorrect_reasoning: JSON.stringify({ A: 'Effect as verb means to bring about, not to influence', C: 'Effect should be the noun here', D: 'Grammatically incorrect' }), skill_tag: 'word_choice', difficulty: 'medium', strategy_tip: 'Affect = verb (to influence). Effect = noun (the result). RAVEN: Remember Affect Verb Effect Noun.' },
  { section: 'english', question_text: 'Which sentence avoids a split infinitive?', passage: null, options: JSON.stringify(['A) She wants to quickly finish the report.', 'B) She wants to finish the report quickly.', 'C) She quickly wants to finish the report.', 'D) She to quickly finish wants the report.']), correct_answer: 'B', explanation: 'Placing quickly after the infinitive avoids splitting to...finish.', incorrect_reasoning: JSON.stringify({ A: 'Splits to...finish with quickly', C: 'Modifies wants not finish', D: 'Incomprehensible' }), skill_tag: 'modifier_placement', difficulty: 'hard', strategy_tip: 'Avoid placing adverbs between to and the verb in formal writing.' },
  { section: 'english', question_text: 'Which sentence correctly uses "its" vs "it\'s"?', passage: null, options: JSON.stringify(['A) Its going to rain today.', 'B) The cat licked it\'s paw.', 'C) It\'s been a long day.', 'D) The dog wagged it\'s tail.']), correct_answer: 'C', explanation: 'It\'s = it is. It\'s been = It has been. Its = possessive.', incorrect_reasoning: JSON.stringify({ A: 'Should be it\'s (it is)', B: 'Should be its (possessive)', D: 'Should be its (possessive)' }), skill_tag: 'grammar_usage', difficulty: 'easy', strategy_tip: 'It\'s = it is/it has. Its = possessive (no apostrophe).' },
  { section: 'english', question_text: 'Which provides the strongest supporting evidence?', passage: 'Climate change is accelerating. _____', options: JSON.stringify(['A) Many people are concerned.', 'B) Arctic ice has decreased 40% since 1979, with 2023 marking the hottest year on record.', 'C) It has been getting warmer.', 'D) Scientists study climate.']), correct_answer: 'B', explanation: 'Specific data (40%, dates, records) provides strong evidence.', incorrect_reasoning: JSON.stringify({ A: 'Opinion not evidence', C: 'Vague restatement', D: 'Irrelevant fact' }), skill_tag: 'organization', difficulty: 'hard', strategy_tip: 'Strong evidence: specific numbers, dates, and verifiable facts.' },
  { section: 'english', question_text: 'Which sentence correctly uses the past perfect?', passage: null, options: JSON.stringify(['A) She had went to the store before I called.', 'B) She had gone to the store before I called.', 'C) She has gone to the store before I called.', 'D) She gone to the store before I called.']), correct_answer: 'B', explanation: 'Past perfect = had + past participle (gone, not went).', incorrect_reasoning: JSON.stringify({ A: 'Went is past tense, not past participle', C: 'Present perfect with past context', D: 'Missing auxiliary had' }), skill_tag: 'verb_tense', difficulty: 'medium', strategy_tip: 'Past perfect: had + past participle (gone, written, eaten).' },
  { section: 'english', question_text: 'Which revision makes the sentence concise? "There are many students who enjoy playing basketball."', passage: null, options: JSON.stringify(['A) Many students enjoy playing basketball.', 'B) There are many students playing basketball who enjoy it.', 'C) Playing basketball is enjoyed by many students who are there.', 'D) Many students are there who enjoy basketball playing.']), correct_answer: 'A', explanation: 'Eliminates "There are...who" construction for directness.', incorrect_reasoning: JSON.stringify({ B: 'More wordy', C: 'Passive and wordy', D: 'Awkward construction' }), skill_tag: 'style', difficulty: 'easy', strategy_tip: 'Eliminate "there are/it is" constructions when possible.' },
  { section: 'english', question_text: 'Which sentence has correct parallel structure? "The manager asked staff to arrive early, to prepare reports, and _____."', passage: null, options: JSON.stringify(['A) attending the meeting', 'B) to attend the meeting', 'C) that they attend the meeting', 'D) attendance at the meeting']), correct_answer: 'B', explanation: 'Matching infinitive form: to arrive, to prepare, to attend.', incorrect_reasoning: JSON.stringify({ A: 'Gerund breaks pattern', C: 'That-clause breaks pattern', D: 'Noun breaks pattern' }), skill_tag: 'parallelism', difficulty: 'medium', strategy_tip: 'Match the grammatical form of preceding items in the series.' },
  { section: 'english', question_text: 'Which correctly handles subject-verb agreement with an intervening clause?', passage: null, options: JSON.stringify(['A) The box of chocolates are on the table.', 'B) The box of chocolates is on the table.', 'C) The box of chocolates were on the table.', 'D) The box of chocolates have been on the table.']), correct_answer: 'B', explanation: 'Subject is box (singular), not chocolates. Ignore the prepositional phrase.', incorrect_reasoning: JSON.stringify({ A: 'Are agrees with chocolates not box', C: 'Were agrees with chocolates', D: 'Have agrees with chocolates' }), skill_tag: 'grammar_usage', difficulty: 'medium', strategy_tip: 'The subject is never inside a prepositional phrase (of, in, with, etc.).' },
  { section: 'english', question_text: 'Which correctly places a restrictive clause?', passage: null, options: JSON.stringify(['A) Students, who complete homework, earn credit.', 'B) Students who complete homework earn credit.', 'C) Students who complete homework, earn credit.', 'D) Students, who complete homework earn credit.']), correct_answer: 'B', explanation: 'Restrictive clause (essential to meaning—identifies which students) has no commas.', incorrect_reasoning: JSON.stringify({ A: 'Commas make it nonrestrictive (implies all students)', C: 'Extra comma separates subject from verb', D: 'Missing closing comma creates confusion' }), skill_tag: 'sentence_structure', difficulty: 'hard', strategy_tip: 'Restrictive (essential) = no commas. Nonrestrictive (extra info) = commas.' },
];

